input.command:
NS="karma-rabbitmq-compliance-sweep-20260-ceb861cd-cluster-a"

# Add TLS volume to StatefulSet (add to volumes array)
kubectl -n "$NS" patch statefulset rabbitmq --type='json' -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/volumes/-",
    "value": {
      "name": "tls",
      "secret": {
        "secretName": "rabbitmq-tls",
        "defaultMode": 256
      }
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "tls",
      "mountPath": "/etc/rabbitmq/tls",
      "readOnly": true
    }
  }
]'
echo "StatefulSet patched with TLS volume"

