input.command:
NS="karma-rabbitmq-compliance-sweep-20260-ceb861cd-cluster-a"

# Add TLS port 5671 to the rabbitmq ClusterIP service
kubectl -n "$NS" patch service rabbitmq --type='json' -p='[
  {"op":"add","path":"/spec/ports/-","value":{"name":"amqps","port":5671,"protocol":"TCP","targetPort":5671}}
]'

# Add TLS port 5671 to the rabbitmq-headless service
kubectl -n "$NS" patch service rabbitmq-headless --type='json' -p='[
  {"op":"add","path":"/spec/ports/-","value":{"name":"amqps","port":5671,"protocol":"TCP","targetPort":5671}}
]'

echo "Services updated:"
kubectl -n "$NS" get svc
